class LoginViewController: UIViewController {

    override func viewDidLoad() {
        super.viewDidLoad()
        view.backgroundColor = .white
        setupUI()
    }

    override func viewDidAppear(_ animated: Bool) {
        super.viewDidAppear(animated)
        if BiometricAuthenticationManager.shared.isAuthenticated {
            // User is already authenticated, bypass login
            navigateToAppContent()
        } else {
            // Try to authenticate if not already authenticated
            attemptBiometricAuthentication()
        }
    }

    private func setupUI() {
        let loginButton = UIButton(type: .system)
        loginButton.setTitle("Login with Password", for: .normal)
        loginButton.addTarget(self, action: #selector(loginWithPassword), for: .touchUpInside)
        loginButton.frame = CGRect(x: 50, y: 300, width: view.bounds.width - 100, height: 50)
        view.addSubview(loginButton)

        let biometricButton = UIButton(type: .system)
        biometricButton.setTitle("Authenticate with Biometrics", for: .normal)
        biometricButton.addTarget(self, action: #selector(attemptBiometricAuthentication), for: .touchUpInside)
        biometricButton.frame = CGRect(x: 50, y: 360, width: view.bounds.width - 100, height: 50)
        view.addSubview(biometricButton)
    }

    @objc private func attemptBiometricAuthentication() {
        let reason: String
        switch BiometricAuthenticationManager.shared.biometricType() {
        case .faceID:
            reason = "Authenticate with Face ID to access your account."
        case .touchID:
            reason = "Authenticate with Touch ID to access your account."
        case .none:
            showAlert(title: "Biometrics Not Available", message: "Your device does not support Face ID or Touch ID, or it is not configured. Please login with password.")
            return
        @unknown default:
            reason = "Authenticate to access your account."
        }


        BiometricAuthenticationManager.shared.authenticateUser(reason: reason) { result in
            switch result {
            case .success(true):
                self.navigateToAppContent()
            case .failure(let error):
                self.handleBiometricError(error)
            case .success(false): // Should not happen with current implementation but good for exhaustiveness
                self.showAlert(title: "Authentication Failed", message: "Biometric authentication failed.")
            }
        }
    }

    private func handleBiometricError(_ error: LAError) {
        var errorMessage = "Biometric authentication failed."
        switch error.code {
        case .appCancel:
            errorMessage = "Authentication was cancelled by the application."
        case .userCancel:
            errorMessage = "Authentication was cancelled by the user."
        case .userFallback:
            errorMessage = "User chose to enter password. Please use the 'Login with Password' button."
        case .biometryNotAvailable:
            errorMessage = "Biometric authentication is not available on this device."
        case .biometryLockout:
            errorMessage = "Biometric authentication is locked out. Please try again later or use your password."
        case .biometryNotEnrolled:
            errorMessage = "No biometrics enrolled on this device. Please enroll Face ID or Touch ID in your device settings."
        case .passcodeNotSet:
            errorMessage = "Device passcode is not set. Please set a passcode to use biometrics."
        default:
            errorMessage = "Authentication failed: \(error.localizedDescription)"
        }

        let alert = UIAlertController(title: "Authentication Error", message: errorMessage, preferredStyle: .alert)
        if error.code == .userFallback {
            alert.addAction(UIAlertAction(title: "OK", style: .default, handler: nil))
        } else {
            alert.addAction(UIAlertAction(title: "Try Again", style: .default) { _ in
                self.attemptBiometricAuthentication()
            })
            alert.addAction(UIAlertAction(title: "Login with Password", style: .cancel) { _ in
                self.loginWithPassword() // Direct to password login
            })
        }
        present(alert, animated: true, completion: nil)
    }

    @objc private func loginWithPassword() {
        showAlert(title: "Login with Password", message: "Here you would present your password login screen.")
        // In a real app, this would present a text field for username/password
        // and then navigateToAppContent() upon successful password verification.
        BiometricAuthenticationManager.shared.isAuthenticated = true // Simulate password login success
        navigateToAppContent()
    }

    private func navigateToAppContent() {
        let appContentVC = AppContentViewController()
        appContentVC.modalPresentationStyle = .fullScreen
        present(appContentVC, animated: true, completion: nil)
    }

    private func showAlert(title: String, message: String) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default, handler: nil))
        present(alert, animated: true, completion: nil)
    }
